export function createScreenStatusNodes() {
    const loadingNode = document.createElement('p');
    loadingNode.className = 'screen-loading';
    loadingNode.hidden = true;
    loadingNode.textContent = 'Loading...';

    const errorNode = document.createElement('pre');
    errorNode.className = 'screen-error';
    errorNode.hidden = true;

    const retryNode = document.createElement('button');
    retryNode.className = 'screen-retry';
    retryNode.hidden = true;
    retryNode.textContent = 'Retry';

    return { loadingNode, errorNode, retryNode };
}

export function createScreenStatusMixin(
    loadingNode: HTMLElement,
    errorNode: HTMLElement,
    retryNode: HTMLElement
) {
    return {
        setLoading() {
            loadingNode.hidden = false;
            errorNode.hidden = true;
            retryNode.hidden = true;
        },
        setError(err: unknown) {
            loadingNode.hidden = true;
            errorNode.hidden = false;
            retryNode.hidden = false;

            if (err instanceof Error) {
                errorNode.textContent = err.stack ?? err.message;
            } else {
                errorNode.textContent = String(err);
            }
        },
        clearStatus() {
            loadingNode.hidden = true;
            errorNode.hidden = true;
            retryNode.hidden = true;
        }
    };
}
